import React from 'react';
import { Card, Stack, Divider, Text, Heading } from '@ggui-ai/design/primitives';

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit?: string;
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent(props: Props) {
  const {
    city = 'Unknown City',
    temperature = 0,
    condition = 'N/A',
    humidity = 0,
    windSpeed = 0,
    unit = 'C',
    forecast = [],
  } = props;

  return (
    <Card shadow="md" padding={24} radius="lg">
      <Stack gap={24}>
        <Stack direction="horizontal" justify="between" align="center">
          <Heading level={3}>{city}</Heading>
          <Text variant="bodyLarge">{condition}</Text>
        </Stack>

        <Stack align="center" gap={4}>
          <Heading level={1} color="var(--ggui-color-primary-600, #0284c7)">
            {temperature}°{unit}
          </Heading>
        </Stack>

        <Stack direction="horizontal" justify="around">
          <Stack align="center" gap={4}>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Humidity</Text>
            <Text variant="body">{humidity}%</Text>
          </Stack>
          <Stack align="center" gap={4}>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Wind</Text>
            <Text variant="body">{windSpeed} km/h</Text>
          </Stack>
        </Stack>

        <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

        <Stack direction="horizontal" justify="between">
          {forecast.map((item, index) => (
            <Stack key={index} align="center" gap={8}>
              <Text variant="caption" weight="medium">{item.day ?? '--'}</Text>
              <Text size="xl">{item.icon ?? '☁️'}</Text>
              <Stack direction="horizontal" gap={4}>
                <Text variant="bodySmall" weight="semibold">{item.high}°</Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">{item.low}°</Text>
              </Stack>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useMemo } from 'react';
import { Container, Stack, Box, Text, Heading, Card, Divider, Spacer } from '@ggui-ai/design/primitives';
import { Badge } from '@ggui-ai/design/components';

interface Element {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  elements?: Element[];
}

export default function GeneratedComponent(props: Props) {
  const { elements = [] } = props;
  const [searchQuery, setSearchQuery] = useState('');
  const [selected, setSelected] = useState<Element | null>(null);

  const filteredElements = useMemo(() => {
    if (!searchQuery) return elements;
    const q = searchQuery.toLowerCase();
    return elements.filter(
      (e) =>
        e.name?.toLowerCase().includes(q) ||
        e.symbol?.toLowerCase().includes(q)
    );
  }, [elements, searchQuery]);

  const categories = useMemo(() => Array.from(new Set(elements.map((e) => e.category))), [elements]);

  const getCategoryColor = (cat?: string) => {
    switch (cat) {
      case 'nonmetal': return 'var(--ggui-color-primary-200)';
      case 'noble-gas': return 'var(--ggui-color-info-100)';
      case 'alkali-metal': return 'var(--ggui-color-warning-100)';
      default: return 'var(--ggui-color-neutral-100)';
    }
  };

  return (
    <Container maxWidth="full" padding={32}>
      <Stack gap={24}>
        <Stack gap={8}>
          <Text as="label" htmlFor="search-el" weight="medium">Search Elements</Text>
          <Box as="input" id="search-el" value={searchQuery} onChange={(e: any) => setSearchQuery(e.target.value)} />
        </Stack>

        <Box 
          style={{ 
            display: 'grid', 
            gridTemplateColumns: 'repeat(18, 1fr)', 
            gap: 8,
            alignItems: 'start'
          }}
        >
          {elements.map((el) => {
            const isMatch = filteredElements.includes(el);
            return (
              <Box
                key={el.atomicNumber}
                style={{ 
                  gridRow: el.row, 
                  gridColumn: el.col,
                  opacity: isMatch ? 1 : 0.2,
                  transition: 'all 200ms ease-in-out',
                  cursor: 'pointer'
                }}
                background={getCategoryColor(el.category)}
                borderRadius="sm"
                padding={8}
                onClick={() => setSelected(el)}
              >
                <Text variant="caption">{el.atomicNumber}</Text>
                <Heading level={4}>{el.symbol}</Heading>
              </Box>
            );
          })}
        </Box>

        <Stack direction="horizontal" gap={8} wrap>
          {categories.map((cat) => (
            <Badge key={cat} style={{ backgroundColor: getCategoryColor(cat) }}>{cat ?? 'unknown'}</Badge>
          ))}
        </Stack>

        {selected && (
          <Card shadow="md" padding={24}>
            <Heading level={3}>{selected.name}</Heading>
            <Divider margin={16} />
            <Stack gap={8}>
              <Text><strong>Symbol:</strong> {selected.symbol}</Text>
              <Text><strong>Atomic Number:</strong> {selected.atomicNumber}</Text>
              <Text><strong>Atomic Weight:</strong> {selected.atomicWeight}</Text>
              <Text><strong>Category:</strong> {selected.category}</Text>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}
